class Solution {
    public String removeOccurrences(String s, String part) {
        int index = findFirstOccurrence(s, part);
        while (index != -1) {
            index = findNextOccurrence(s, part, index);
            s = removeCharAt(s, index);
        }
        return s;
    }

    private int findFirstOccurrence(String s, String part) {
        int startIndex = s.indexOf(part);
        if (startIndex == -1) {
            return -1;
        }
        return startIndex;
    }

    private String removeCharAt(String s, int index) {
        StringBuilder result = new StringBuilder(s);
        result.deleteCharAt(index);
        return result.toString();
    }

    private int findNextOccurrence(String s, String part, int startIndex) {
        int index = startIndex;
        while (index != -1 && index < s.length()) {
            index = findNextOccurrence(s, part, index + 1);
        }
        return index;
    }
}
